#include <bits/stdc++.h>
using namespace std;

struct Line {
	int a, b;
} l[1000005];

bool cmp(Line a, Line b) {
	return a.a < b.a;
}

int main() {
	int n, ans = 0, last_b;
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> l[i].a >> l[i].b;
	}
	sort(l, l + n, cmp);
	for (int i = 0; i < n; ) {
		ans++;
		last_b = l[i].b;
		do {
			i++;
		} while (l[i].a < last_b && (i < n));
	}
	cout << ans;
	return 0;
}
